import{_ as a,o,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Sistema Anti Yo-Yo","description":"","frontmatter":{},"headers":[],"relativePath":"es/advanced/anti-yoyo.md","filePath":"es/advanced/anti-yoyo.md"}'),l={name:"es/advanced/anti-yoyo.md"};function t(s,e,r,c,d,u){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="sistema-anti-yo-yo" tabindex="-1"><i class="ph ph-arrows-clockwise"></i> Sistema Anti Yo-Yo <a class="header-anchor" href="#sistema-anti-yo-yo" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-arrows-clockwise&quot;&gt;&lt;/i&gt; Sistema Anti Yo-Yo&quot;">​</a></h1><p>Uno de los problemas más irritantes de los sistemas de escalado dinámico es el <strong>Efecto Yo-Yo</strong> (o ping-pong de calidad).</p><h2 id="el-problema-central" tabindex="-1"><i class="ph ph-warning-circle"></i> El Problema Central <a class="header-anchor" href="#el-problema-central" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-warning-circle&quot;&gt;&lt;/i&gt; El Problema Central&quot;">​</a></h2><p>Sin un control inteligente, el sistema entra en un bucle infinito:</p><ol><li>Los FPS caen debido a una escena pesada.</li><li>El plugin reduce la calidad gráfica (e.g., corta la resolución).</li><li>La carga disminuye y los FPS suben por encima de la línea base.</li><li>El plugin deduce que hay Margen de Rendimiento (Performance Headroom) disponible y restaura la calidad gráfica al máximo.</li><li>Los FPS caem de nuevo. El ciclo se repite.</li></ol><p>En consecuencia, el jugador sufre un parpadeo continuo de calidad (Quality flickering): las sombras aparecen y desaparecen constantemente, y la imagen &quot;salta&quot; cada segundo de borrosa a nítida.</p><h2 id="la-solucion-webap-bloqueo-de-penalizacion" tabindex="-1"><i class="ph ph-shield-check"></i> La Solución WebAP: Bloqueo de Penalización <a class="header-anchor" href="#la-solucion-webap-bloqueo-de-penalizacion" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-shield-check&quot;&gt;&lt;/i&gt; La Solución WebAP: Bloqueo de Penalización&quot;">​</a></h2><p>Erradicamos completamente este problema implementando el concepto de un Bloqueo de Penalización (Penalty Lockout). Se basa en dos parámetros de la configuración del plugin.</p><p>Cuando el plugin <em>aumenta</em> la calidad gráfica, activa un temporizador oculto: la <strong>Detection Window</strong> (por ejemplo, 15 segundos). Durante este período de tiempo, el Indexer supervisa de cerca la estabilidad del fotograma.</p><p>Si los FPS caen repentinamente durante esta ventana, el sistema saca una conclusión definitiva: <em>«La mejora gráfica anterior fue un error; el dispositivo no puede mantener este nivel a larga distancia.»</em></p><p><strong>Se aplica una penalización:</strong></p><ol><li>El plugin disminuye inmediatamente la calidad de nuevo.</li><li>Se aplica una estricta <strong>Penalty Lockout Duration</strong> (por ejemplo, durante 60 segundos).</li><li>Durante la duración de este minuto, se le <strong>prohíbe categóricamente</strong> al plugin intentar aumentar la calidad gráfica nuevamente, incluso si los FPS se disparan y el procesador se inactiva.</li></ol><div class="tip custom-block"><p class="custom-block-title">Bloqueo de Sesión (Session Lock)</p><p>Si la dinámica de tu juego presenta picos de carga que ocurren en oleadas, y prefieres que la calidad nunca intente recuperarse después de la primera caída, simplemente especifica un valor masivo en el campo <strong>Penalty Lockout Duration</strong> (por ejemplo, <code>600</code> para 10 minutos o <code>3600</code> para una hora). Esto bloquea efectivamente los gráficos en un nivel bajo constante hasta el final de la sesión de juego.</p></div><div class="info custom-block"><p class="custom-block-title">Prioridad de Fluidez</p><p>La penalización bloquea exclusivamente los intentos de mejorar el renderizado. Si el jugador entra en una escena aún más pesada y los FPS caen por debajo del umbral crítico, el plugin aún puede disminuir la calidad con urgencia. El sistema invariablemente prioriza la fluidez del juego sobre los efectos visuales.</p></div>',14)])])}const g=a(l,[["render",t]]);export{m as __pageData,g as default};
